1	import React, { useRef, useState } from 'react';
2	import { cn } from '@/lib/utils';
3	import { ChevronDown } from 'lucide-react';
4	import gsap from 'gsap';
5	import { useGSAP } from '@gsap/react';
6	
7	interface ExpandableSectionProps {
8	  toggleLabel: string;
9	  hintText?: string;
10	  children: React.ReactNode;
11	  className?: string;
12	}
13	
14	const ExpandableSection: React.FC<ExpandableSectionProps> = ({
15	  toggleLabel,
16	  hintText = 'Click to expand',
17	  children,
18	  className,
19	}) => {
20	  const [isOpen, setIsOpen] = useState(false);
21	  const contentRef = useRef<HTMLDivElement>(null);
22	
23	  useGSAP(() => {
24	    if (!contentRef.current) return;
25	
26	    if (isOpen) {
27	      gsap.fromTo(
28	        contentRef.current,
29	        { height: 0, opacity: 0 },
30	        { height: 'auto', opacity: 1, duration: 0.35, ease: 'power2.out' }
31	      );
32	    } else {
33	      gsap.to(contentRef.current, {
34	        height: 0,
35	        opacity: 0,
36	        duration: 0.35,
37	        ease: 'power2.out',
38	      });
39	    }
40	  }, [isOpen]);
41	
42	  return (
43	    <div className={cn('w-full', className)}>
44	      <button
45	        onClick={() => setIsOpen(!isOpen)}
46	        className={cn(
47	          'w-full flex items-center justify-between px-5 py-3.5 rounded-xl border transition-colors duration-200',
48	          'bg-[var(--bg-accent)] border-[var(--border)] hover:bg-[var(--bg-accent)]/80'
49	        )}
50	        aria-expanded={isOpen}
51	      >
52	        <div className="flex items-center gap-2">
53	          <ChevronDown
54	            className={cn(
55	              'w-4 h-4 text-[var(--primary)] transition-transform duration-300',
56	              isOpen && 'rotate-180'
57	            )}
58	          />
59	          <span className="text-body-sm font-semibold text-[var(--primary)]">
60	            {toggleLabel}
61	          </span>
62	        </div>
63	        <span className="text-caption text-[var(--text-light)]">{hintText}</span>
64	      </button>
65	      <div
66	        ref={contentRef}
67	        className="overflow-hidden"
68	        style={{ height: 0, opacity: 0 }}
69	      >
70	        <div className="px-5 py-5 rounded-b-xl bg-[var(--bg-primary)] border border-t-0 border-[var(--border)]">
71	          {children}
72	        </div>
73	      </div>
74	    </div>
75	  );
76	};
77	
78	export default ExpandableSection;
