import React, { useRef, memo, useState, useCallback } from 'react';
import gsap from 'gsap';
import { useGSAP } from '@gsap/react';
import {
  Brain,
  Layers,
  Minimize2,
  Settings,
  Lightbulb,
  Eye,
  EyeOff,
  Play,
  RotateCcw,
} from 'lucide-react';
import Badge from '@/components/Badge';
import FeatureCard from '@/components/FeatureCard';
import ExpandableSection from '@/components/ExpandableSection';

interface SlideProps {
  isActive: boolean;
}

const CONTEXT_BLOCKS = [
  '系统提示词：你是一个AI助手...',
  '用户历史对话第1轮...',
  '用户历史对话第2轮...',
  '工具调用结果：数据库返回156条记录...',
  '长文档内容：公司运维规范第三章...',
  '上一轮分析报告：共计12页...',
  '邮件历史：最近30封邮件摘要...',
  '知识库检索：匹配到47条相关文档...',
  '代码片段：来自3个仓库的diff...',
  '日志分析：过去24小时的告警信息...',
];

const SOLUTIONS = [
  {
    icon: Layers,
    title: '渐进式披露',
    subtitle: 'Progressive Disclosure',
    description:
      '不一次加载所有信息，只按需加载当前任务所需的内容。Skills系统正是这一方案的核心实现。',
    color: 'var(--primary)',
    bgColor: 'var(--bg-accent)',
  },
  {
    icon: Minimize2,
    title: '上下文压缩',
    subtitle: 'Context Compression',
    description:
      '将长对话压缩为紧凑的语义表示。OpenClaw通过Embedding + BM25进行语义记忆搜索，实现高效压缩。',
    color: 'var(--accent)',
    bgColor: '#FFF7ED',
  },
  {
    icon: Settings,
    title: 'Harness工程',
    subtitle: 'Harness Engineering',
    description:
      '预设约束和身份，减少自由探索的开销。OpenClaw的SOUL层和SKILL.md约束机制让模型行为更可预测。',
    color: 'var(--secondary)',
    bgColor: '#ECFDF5',
  },
];

const Slide05_MemoryProblem: React.FC<SlideProps> = ({ isActive }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [simulating, setSimulating] = useState(false);
  const [showSolution, setShowSolution] = useState(false);
  const [visibleBlocks, setVisibleBlocks] = useState(0);
  const blockRefs = useRef<(HTMLDivElement | null)[]>([]);

  useGSAP(
    () => {
      if (!isActive || !containerRef.current) return;

      const ctx = gsap.context(() => {
        const tl = gsap.timeline({ delay: 0.15 });

        // Title
        tl.fromTo(
          '.mem-title',
          { opacity: 0, y: 30 },
          { opacity: 1, y: 0, duration: 0.6, ease: 'power3.out' }
        );

        // Subtitle
        tl.fromTo(
          '.mem-subtitle',
          { opacity: 0, y: 20 },
          { opacity: 1, y: 0, duration: 0.5, ease: 'power3.out' },
          '-=0.3'
        );

        // Context window demo
        tl.fromTo(
          '.mem-context-demo',
          { opacity: 0, y: 30 },
          { opacity: 1, y: 0, duration: 0.6, ease: 'power3.out' },
          '-=0.2'
        );

        // Solution cards stagger
        tl.fromTo(
          '.mem-solution-card',
          { opacity: 0, y: 30 },
          {
            opacity: 1,
            y: 0,
            duration: 0.5,
            stagger: 0.15,
            ease: 'power3.out',
          },
          '-=0.1'
        );

        // Insight bar
        tl.fromTo(
          '.mem-insight',
          { opacity: 0, y: 20 },
          { opacity: 1, y: 0, duration: 0.5, ease: 'power3.out' },
          '-=0.1'
        );

        // Expandable
        tl.fromTo(
          '.mem-expandable',
          { opacity: 0 },
          { opacity: 1, duration: 0.5 },
          '-=0.2'
        );
      }, containerRef);

      return () => ctx.revert();
    },
    { scope: containerRef, dependencies: [isActive] }
  );

  const handleSimulate = useCallback(() => {
    if (simulating) return;
    setSimulating(true);
    setShowSolution(false);
    setVisibleBlocks(0);

    let count = 0;
    const interval = setInterval(() => {
      count++;
      setVisibleBlocks(count);

      // Animate the new block in
      const block = blockRefs.current[count - 1];
      if (block) {
        gsap.fromTo(
          block,
          { opacity: 0, x: -20 },
          { opacity: 1, x: 0, duration: 0.3, ease: 'power2.out' }
        );
      }

      // Fade earlier blocks progressively
      for (let i = 0; i < count - 1; i++) {
        const earlierBlock = blockRefs.current[i];
        if (earlierBlock) {
          const fadeAmount = Math.max(0.15, 1 - (count - 1 - i) * 0.15);
          gsap.to(earlierBlock, {
            opacity: fadeAmount,
            duration: 0.3,
          });
        }
      }

      if (count >= CONTEXT_BLOCKS.length) {
        clearInterval(interval);
        setTimeout(() => setSimulating(false), 500);
      }
    }, 600);
  }, [simulating]);

  const handleSolution = useCallback(() => {
    setShowSolution((prev) => !prev);
  }, []);

  const handleReset = useCallback(() => {
    setVisibleBlocks(0);
    setShowSolution(false);
    setSimulating(false);
  }, []);

  const getBlockOpacity = (index: number, total: number) => {
    if (total <= 1) return 1;
    const fadeAmount = Math.max(0.15, 1 - (total - 1 - index) * 0.15);
    return fadeAmount;
  };

  return (
    <section
      ref={containerRef}
      className="w-full min-h-[100dvh] flex flex-col items-center justify-center px-6 py-16"
      style={{ backgroundColor: 'var(--bg-primary)' }}
    >
      <div className="w-full max-w-6xl mx-auto flex flex-col items-center">
        {/* Header */}
        <div className="text-center mb-8">
          <div className="mem-title" style={{ opacity: 0 }}>
            <Badge variant="accent" className="mb-3">
              核心问题 #1
            </Badge>
          </div>
          <h2
            className="mem-title text-h1 font-extrabold"
            style={{ color: 'var(--primary)', opacity: 0 }}
          >
            记忆问题
          </h2>
          <p
            className="mem-subtitle text-body mt-3 max-w-2xl mx-auto"
            style={{ color: 'var(--text-secondary)', opacity: 0 }}
          >
            上下文记忆能力有限 -- 注意力稀释导致"越聊越笨"
          </p>
        </div>

        {/* Interactive Context Window Demo */}
        <div
          className="mem-context-demo w-full grid grid-cols-1 md:grid-cols-2 gap-6 mb-8"
          style={{ opacity: 0 }}
        >
          {/* Left: Context Window Visualization */}
          <div
            className="flex flex-col p-5 rounded-2xl border-2"
            style={{
              borderColor: 'var(--border)',
              backgroundColor: 'var(--card-bg)',
            }}
          >
            <div className="flex items-center justify-between mb-4">
              <div className="flex items-center gap-2">
                <Brain
                  className="w-5 h-5"
                  style={{ color: 'var(--primary)' }}
                  strokeWidth={2}
                />
                <span
                  className="text-h3 font-bold"
                  style={{ color: 'var(--text-primary)' }}
                >
                  上下文窗口
                </span>
              </div>
              <span
                className="text-caption font-mono"
                style={{ color: 'var(--text-secondary)' }}
              >
                {visibleBlocks}/{CONTEXT_BLOCKS.length} blocks
              </span>
            </div>

            {/* Context blocks container */}
            <div
              className="flex flex-col gap-1.5 mb-4 overflow-y-auto"
              style={{
                maxHeight: 260,
                minHeight: 260,
                scrollbarWidth: 'thin',
              }}
            >
              {visibleBlocks === 0 && (
                <div
                  className="flex items-center justify-center h-full text-caption"
                  style={{ color: 'var(--text-secondary)' }}
                >
                  点击下方按钮开始模拟...
                </div>
              )}
              {CONTEXT_BLOCKS.slice(0, visibleBlocks).map((block, i) => (
                <div
                  key={i}
                  ref={(el) => {
                    blockRefs.current[i] = el;
                  }}
                  className="px-3 py-2 rounded-lg text-caption font-mono truncate"
                  style={{
                    backgroundColor: 'var(--bg-secondary)',
                    color: 'var(--text-primary)',
                    borderLeft: `3px solid ${
                      i < visibleBlocks - 3
                        ? 'var(--border)'
                        : i < visibleBlocks - 1
                        ? 'var(--secondary)'
                        : 'var(--primary)'
                    }`,
                  }}
                >
                  {block}
                </div>
              ))}
              {visibleBlocks > 3 && (
                <div
                  className="text-center text-caption font-semibold py-1"
                  style={{ color: 'var(--accent)' }}
                >
                  注意力已稀释! 早期内容被"遗忘"
                </div>
              )}
            </div>

            {/* Controls */}
            <div className="flex items-center gap-2">
              <button
                onClick={handleSimulate}
                disabled={simulating}
                className="flex items-center gap-1.5 px-4 py-2 rounded-lg text-caption font-semibold transition-all duration-200 hover:scale-105 disabled:opacity-50"
                style={{
                  backgroundColor: 'var(--primary)',
                  color: '#FFFFFF',
                }}
              >
                <Play className="w-3.5 h-3.5" strokeWidth={2} />
                {simulating ? '模拟中...' : '模拟注意力稀释'}
              </button>
              <button
                onClick={handleReset}
                className="flex items-center gap-1.5 px-3 py-2 rounded-lg text-caption font-semibold border transition-all duration-200 hover:bg-[var(--bg-secondary)]"
                style={{
                  borderColor: 'var(--border)',
                  color: 'var(--text-secondary)',
                }}
              >
                <RotateCcw className="w-3.5 h-3.5" strokeWidth={2} />
                重置
              </button>
              <button
                onClick={handleSolution}
                className="flex items-center gap-1.5 px-3 py-2 rounded-lg text-caption font-semibold border transition-all duration-200 hover:bg-[var(--bg-secondary)]"
                style={{
                  borderColor: showSolution ? 'var(--success)' : 'var(--border)',
                  color: showSolution ? 'var(--success)' : 'var(--text-secondary)',
                  backgroundColor: showSolution ? 'rgba(16,185,129,0.08)' : 'transparent',
                }}
              >
                {showSolution ? (
                  <Eye className="w-3.5 h-3.5" strokeWidth={2} />
                ) : (
                  <EyeOff className="w-3.5 h-3.5" strokeWidth={2} />
                )}
                {showSolution ? '已开启方案' : '查看解决方案'}
              </button>
            </div>

            {/* Solution overlay */}
            {showSolution && (
              <div
                className="mt-3 p-3 rounded-xl border"
                style={{
                  backgroundColor: 'rgba(16,185,129,0.06)',
                  borderColor: 'var(--success)',
                }}
              >
                <p
                  className="text-caption font-semibold"
                  style={{ color: 'var(--success)' }}
                >
                  Skills渐进式加载：只加载当前需要的1-2个Skill指令，
                  而非全部上下文。Token消耗从50K降至2.7K，节省94%。
                </p>
              </div>
            )}
          </div>

          {/* Right: Three Solutions */}
          <div className="flex flex-col gap-3">
            {SOLUTIONS.map((solution, idx) => (
              <div
                key={solution.title}
                className="mem-solution-card"
                style={{ opacity: 0 }}
              >
                <FeatureCard
                  icon={solution.icon}
                  title={solution.title}
                  description={solution.description}
                  badge={
                    <Badge
                      variant={
                        idx === 0
                          ? 'primary'
                          : idx === 1
                          ? 'accent'
                          : 'success'
                      }
                    >
                      {solution.subtitle}
                    </Badge>
                  }
                />
              </div>
